import{_ as e,o as i,c as s,a2 as t}from"./chunks/framework.BKG_UbFK.js";const k=JSON.parse('{"title":"الترحيل من تثبيت Spatie موجود مسبقاً","description":"","frontmatter":{},"headers":[],"relativePath":"ar/guide/migration.md","filePath":"ar/guide/migration.md"}'),d={name:"ar/guide/migration.md"};function c(l,a,o,r,n,h){return i(),s("div",null,[...a[0]||(a[0]=[t(`<h1 id="الترحيل-من-تثبيت-spatie-موجود-مسبقاً" tabindex="-1">الترحيل من تثبيت Spatie موجود مسبقاً <a class="header-anchor" href="#الترحيل-من-تثبيت-spatie-موجود-مسبقاً" aria-label="Permalink to &quot;الترحيل من تثبيت Spatie موجود مسبقاً&quot;">​</a></h1><p>إذا كان تطبيقك يستخدم بالفعل <code>spatie/laravel-permission</code> مع أدوار وصلاحيات وتعيينات موجودة، فإن <code>clearance:install</code> تكتشفها وتحافظ عليها - فهي لا تُشغّل ترحيلات (migrations) Spatie أبداً إذا كان جدول <code>roles</code> موجوداً بالفعل. انظر <a href="/clearance-docs/ar/guide/installation.html">التثبيت</a> للاطلاع على تدفق التثبيت الكامل.</p><p>بعد التثبيت، استخدم <code>clearance:backfill</code> لتبنّي بيانات Clearance الوصفية الخاصة بها على أدوارك وحراسك الموجودة.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:backfill</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # meta + role scope + guards</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:backfill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --only=meta</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # just one section</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:backfill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dry-run</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # preview, no writes</span></span></code></pre></div><h2 id="ما-يقوم-به-كل-قسم" tabindex="-1">ما يقوم به كل قسم <a class="header-anchor" href="#ما-يقوم-به-كل-قسم" aria-label="Permalink to &quot;ما يقوم به كل قسم&quot;">​</a></h2><table tabindex="0"><thead><tr><th>القسم</th><th>التأثير</th></tr></thead><tbody><tr><td><code>meta</code></td><td>يُنشئ اسم عرض في <code>clr_meta</code> (اسم الدور بصيغة عناوين) لكل دور لا يمتلك واحداً.</td></tr><tr><td><code>roles</code></td><td>يُنشئ القيم الافتراضية لـ <code>clr_role_meta</code> (<code>scope=global</code>، <code>is_locked=false</code>) لكل دور لا يمتلك واحداً.</td></tr><tr><td><code>guards</code></td><td>يستورد الحراس من <code>config(&#39;auth.guards&#39;)</code> إلى <code>clr_guards</code>، مُصفّاة حسب <code>allowed_guard_drivers</code>.</td></tr></tbody></table><p>استخدم <code>--only=&lt;section&gt;</code> لتشغيل قسم واحد فقط بدلاً من الأقسام الثلاثة.</p><div class="tip custom-block"><p class="custom-block-title">قابل للإعادة (Idempotent)</p><p>جميع الأقسام قابلة للإعادة - إعادة تشغيل <code>clearance:backfill</code> آمنة ولن تُكرّر أو تستبدل صفوف <code>clr_*</code> الموجودة.</p></div><h2 id="الحالات-الطرفية" tabindex="-1">الحالات الطرفية <a class="header-anchor" href="#الحالات-الطرفية" aria-label="Permalink to &quot;الحالات الطرفية&quot;">​</a></h2><p>يحتوي مستودع الحزمة على دليل ترحيل أعمق يغطي حالات طرفية لم يتم تلخيصها هنا - وعلى وجه الخصوص ما يحدث عندما تحتوي قاعدة بياناتك بالفعل على دور باسم <code>super_admin</code> (أو اسم بديل مثل <code>superadmin</code>، <code>root</code>، <code>owner</code>) يتعارض مع دور <code>super_admin</code> الخاص بـ Clearance نفسها، بالإضافة إلى ملاحظات حول الفئات الفرعية المخصصة لنماذج <code>Role</code>/<code>Permission</code> وسلوك استيراد الحراس. اقرأه قبل تشغيل الترحيل على قاعدة بيانات إنتاجية تحتوي على بيانات أدوار موجودة غير بسيطة. انظر أيضاً <a href="/clearance-docs/ar/features/super-admin.html">المشرف الفائق</a> لمعرفة سلوك كشف الأسماء البديلة أثناء <code>clearance:install</code>.</p><h2 id="ذو-صلة" tabindex="-1">ذو صلة <a class="header-anchor" href="#ذو-صلة" aria-label="Permalink to &quot;ذو صلة&quot;">​</a></h2><ul><li><a href="/clearance-docs/ar/guide/installation.html">التثبيت</a> - تدفق <code>clearance:install</code> الكامل</li><li><a href="/clearance-docs/ar/api/artisan-commands.html">أوامر Artisan</a> - المرجع الكامل للأوامر</li><li><a href="/clearance-docs/ar/guide/architecture.html">البنية المعمارية</a> - جداول <code>clr_*</code> التي يملؤها الترحيل</li></ul>`,12)])])}const u=e(d,[["render",c]]);export{k as __pageData,u as default};
